function getActorsFromFolder(folder) {
  if (!folder) {
    return [];
  }
  let actors = [];
  if (Object.hasOwn(folder, "entries")) {
    actors = folder.entries
  } else {
    actors = folder.contents
  }
  const subFolders = folder.children;
  if (subFolders.length > 0) {
    for (let i = 0; i < subFolders.length; i++) {
      actors = actors.concat(getActorsFromFolder(subFolders[i]))
    }
  }
  return actors
}

let folderUUID = "";

try {
  folderUUID = await Dialog.prompt({
      title: "Unset Minion Owner",
      content: `<label>Paste the folder UUID of the folder containing your minions here (click on folder in actors -> edit folder -> copy Document UUID in the top right)</label><input type="text" placeholder="Folder.uuid">`,
      callback: (html) => html.find('input')?.val()
  })
} catch (error) {
  console.log("draw-steel-summoner-class | User closed unsetting minion owner dialog.")
  return;
}

folderUUID = folderUUID.replace("Folder.", "")
const folder = await game.folders.get(folderUUID);

if (!folder) {
  ui.notifications.error(`Could not find folder with UUID ${folderUUID}.`);
  return;
}

let minions = getActorsFromFolder(folder);

if (minions.length <= 0) {
  ui.notifications.error("Found no minions.");
  console.log("draw-steel-summoner-class | Found no minions.")
  return;
}

for (let i = 0; i < minions.length; i++) {
  await minions[i].unsetFlag("world", "ownerUuid");
}
ui.notifications.info(`Unlinked minions in folder.`);
